Code:
public int countClumps(int[] nums) {
    int clumps = 0;
    int i = 0;

    while (i < nums.length - 1) {
        if (nums[i] == nums[i + 1]) {
            clumps++;
            // Move the index 'i' forward until the end of the current clump
            while (i < nums.length - 1 && nums[i] == nums[i + 1]) {
                i++;
            }
        }
        i++;
    }

    return clumps;
}

