public int makeChocolate(int small, int big, int goal) {
    int maxBigBars = goal / 5;
    int useBig = Math.min(maxBigBars, big);
    int remainder = goal - (useBig * 5);
    if (remainder <= small) {
        return remainder;
    } else {
        return -1;
    }
}

