public boolean in1To10(int n, boolean outsideMode) {
    if (outsideMode) {
        // When outsideMode is true, return true if n <= 1 or n >= 10
        return n <= 1 || n >= 10;
    } else {
        // When outsideMode is false, return true if 1 <= n <= 10
        return n >= 1 && n <= 10;
    }
}

