public String alarmClock(int day, boolean vacation) {
    boolean isWeekend = (day == 0 || day == 6); // 0 = Sunday, 6 = Saturday

    if (vacation) {
        // On vacation
        if (isWeekend) {
            return "off";
        } else {
            return "10:00";
        }
    } else {
        // Not on vacation
        if (isWeekend) {
            return "10:00";
        } else {
            return "7:00";
        }
    }
}

