    int sum = 0;
    boolean in67Section = false;

    for (int num : nums) {
        if (in67Section) {
            // If we're in a 6-7 section, check for the end
            if (num == 7) {
                in67Section = false;
            }
            // Otherwise, continue ignoring numbers
        } else {
            // If we encounter a 6, start ignoring until we find a 7
            if (num == 6) {
                in67Section = true;
            } else {
                // Otherwise, add the number to the sum
                sum += num;
            }
        }
    }

